//!
//!     server.route_fn("/api/data", |session| {
//!         send_response(session, HttpStatus::Status200, mime::APPLICATION_JSON, b"{}");
//!     });
//!
//!     // Create reactor
//!     let mut reactor: Reactor<_, _, _> = Reactor::new()?;
//!
//!     // Start server with reactor
